INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Standing_Alternating_Dumbbell_Press','Standing Alternating Dumbbell Press','hombros',ARRAY['tríceps'],'mancuernas','strength',ARRAY['Stand with a dumbbell in each hand. Raise the dumbbells to your shoulders with your palms facing forward and your elbows pointed out. This will be your starting position.','Extend one arm to press the dumbbell straight up, keeping your off hand in place. Do not lean or jerk the weight during the movement.','After a brief pause, return the weight to the starting position.','Repeat for the opposite side, continuing to alternate between arms.'],'Stand with a dumbbell in each hand. Raise the dumbbells to your shoulders with your palms facing forward and your elbows pointed out. This will be your starting position. Extend one arm to press the dumbbell straight up, keeping your off hand in place. Do not lean or jerk the weight during the movement. After a brief pause, return the weight to the starting position. Repeat for the opposite side, continuing to alternate between arms.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Alternating_Dumbbell_Press/0.jpg','exercisedb',true),('Standing_Barbell_Calf_Raise','Standing Barbell Calf Raise','pantorrillas',ARRAY[]::text[],'barra','strength',ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the bar on the back of your shoulders (slightly below the neck).','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. The knees should be kept with a slight bend; never locked. This will be your starting position. Tip: For better range of motion you may also place the ball of your feet on a wooden block but be careful as this option requires more balance and a sturdy block.','Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Repeat for the recommended amount of repetitions.'],'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the bar on the back of your shoulders (slightly below the neck). Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso. Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. The knees should be kept with a slight bend; never locked. This will be your starting position. Tip: For better range of motion you may also place the ball of your feet on a wooden block but be careful as this option requires more balance and a sturdy block. Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down. Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Barbell_Calf_Raise/0.jpg','exercisedb',true),('Standing_Barbell_Press_Behind_Neck','Standing Barbell Press Behind Neck','hombros',ARRAY['tríceps'],'barra','strength',ARRAY['This exercise is best performed inside a squat rack for easier pick up of the bar. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Your back should be kept straight while performing this exercise. This will be your starting position.','Elevate the barbell overhead by fully extending your arms while breathing out.','Hold the contraction for a second and lower the barbell back down to the starting position by inhaling.','Repeat for the recommended amount of repetitions.'],'This exercise is best performed inside a squat rack for easier pick up of the bar. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it. Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso. Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Your back should be kept straight while performing this exercise. This will be your starting position. Elevate the barbell overhead by fully extending your arms while breathing out. Hold the contraction for a second and lower the barbell back down to the starting position by inhaling. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Barbell_Press_Behind_Neck/0.jpg','exercisedb',true),('Standing_Bent-Over_One-Arm_Dumbbell_Triceps_Extension','Standing Bent-Over One-Arm Dumbbell Triceps Extension','tríceps',ARRAY['hombros'],'mancuernas','strength',ARRAY['With a dumbbell in one hand and the palm facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.','The upper arm should be close to the torso and parallel to the floor while the forearm is pointing towards the floor as the hand holds the weight. Tip: There should be a 90-degree angle between the forearm and the upper arm. This is your starting position.','Keeping the upper arms stationary, use the triceps to lift the weights as you exhale until the forearms are parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.','After a second contraction at the top, slowly lower the dumbbell back to the starting position as you inhale.','Repeat the movement for the prescribed amount of repetitions.','Switch arms and repeat the exercise.'],'With a dumbbell in one hand and the palm facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up. The upper arm should be close to the torso and parallel to the floor while the forearm is pointing towards the floor as the hand holds the weight. Tip: There should be a 90-degree angle between the forearm and the upper arm. This is your starting position. Keeping the upper arms stationary, use the triceps to lift the weights as you exhale until the forearms are parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves. After a second contraction at the top, slowly lower the dumbbell back to the starting position as you inhale. Repeat the movement for the prescribed amount of repetitions. Switch arms and repeat the exercise.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Bent-Over_One-Arm_Dumbbell_Triceps_Extension/0.jpg','exercisedb',true),('Standing_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension','Standing Bent-Over Two-Arm Dumbbell Triceps Extension','tríceps',ARRAY[]::text[],'mancuernas','strength',ARRAY['With a dumbbell in each hand and the palms facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up. The upper arms should be close to the torso and parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights. Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.','Keeping the upper arms stationary, use the triceps to lift the weights as you exhale until the forearms are parallel to the floor and the whole arms are extended. Like many other arm exercises, only the forearm moves.','After a second contraction at the top, slowly lower the dumbbells back to their starting position as you inhale.','Repeat the movement for the prescribed amount of repetitions.'],'With a dumbbell in each hand and the palms facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up. The upper arms should be close to the torso and parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights. Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position. Keeping the upper arms stationary, use the triceps to lift the weights as you exhale until the forearms are parallel to the floor and the whole arms are extended. Like many other arm exercises, only the forearm moves. After a second contraction at the top, slowly lower the dumbbells back to their starting position as you inhale. Repeat the movement for the prescribed amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension/0.jpg','exercisedb',true),('Standing_Biceps_Cable_Curl','Standing Biceps Cable Curl','bíceps',ARRAY[]::text[],'cable','strength',ARRAY['Stand up with your torso upright while holding a cable curl bar that is attached to a low pulley. Grab the cable bar at shoulder width and keep the elbows close to the torso. The palm of your hands should be facing up (supinated grip). This will be your starting position.','While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle.','Slowly begin to bring the curl bar back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.'],'Stand up with your torso upright while holding a cable curl bar that is attached to a low pulley. Grab the cable bar at shoulder width and keep the elbows close to the torso. The palm of your hands should be facing up (supinated grip). This will be your starting position. While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle. Slowly begin to bring the curl bar back to starting position as your breathe in. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Biceps_Cable_Curl/0.jpg','exercisedb',true),('Standing_Biceps_Stretch','Standing Biceps Stretch','bíceps',ARRAY['pecho','hombros'],'otro','stretching',ARRAY['Clasp your hands behind your back with your palms together, straighten arms and then rotate them so your palms face downward.','Raise your arms up and hold until you feel a stretch in your biceps.'],'Clasp your hands behind your back with your palms together, straighten arms and then rotate them so your palms face downward. Raise your arms up and hold until you feel a stretch in your biceps.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Biceps_Stretch/0.jpg','exercisedb',true),('Standing_Bradford_Press','Standing Bradford Press','hombros',ARRAY['tríceps'],'barra','strength',ARRAY['Place a loaded bar at shoulder level in a rack. With a pronated grip at shoulder width, begin with the bar racked across the front of your shoulders. This is your starting position.','Initiate the lift by extending the elbows to press the bar overhead. Avoid locking out the elbow as you move the weight behind your head.','Lower the bar down to the back of the head until your elbow forms a right angle.','Lift the bar back over your head by extending the elbows','Lower the bar down to the starting position.','Alternate in this manner until you complete the recommended amount of repetitions.'],'Place a loaded bar at shoulder level in a rack. With a pronated grip at shoulder width, begin with the bar racked across the front of your shoulders. This is your starting position. Initiate the lift by extending the elbows to press the bar overhead. Avoid locking out the elbow as you move the weight behind your head. Lower the bar down to the back of the head until your elbow forms a right angle. Lift the bar back over your head by extending the elbows Lower the bar down to the starting position. Alternate in this manner until you complete the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Bradford_Press/0.jpg','exercisedb',true),('Standing_Cable_Chest_Press','Standing Cable Chest Press','pecho',ARRAY['hombros','tríceps'],'cable','strength',ARRAY['Position dual pulleys to chest height and select an appropriate weight. Stand a foot or two in front of the cables, holding one in each hand. You can stagger your stance for better stability.','Position the upper arm at a 90 degree angle with the shoulder blades together. This will be your starting position.','Keeping the rest of the body stationary, extend through the elbows to press the handles forward, drawing them together in front of you.','Pause at the top of the motion, and return to the starting position.'],'Position dual pulleys to chest height and select an appropriate weight. Stand a foot or two in front of the cables, holding one in each hand. You can stagger your stance for better stability. Position the upper arm at a 90 degree angle with the shoulder blades together. This will be your starting position. Keeping the rest of the body stationary, extend through the elbows to press the handles forward, drawing them together in front of you. Pause at the top of the motion, and return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Cable_Chest_Press/0.jpg','exercisedb',true),('Standing_Cable_Lift','Standing Cable Lift','abdominales',ARRAY['hombros'],'cable','strength',ARRAY['Connect a standard handle on a tower, and move the cable to the lowest pulley position.','With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm''''s length away from the pulley, with the tension of the weight on the cable. Your outstretched arm should be aligned with the cable.','With your feet positioned shoulder width apart, squat down and grab the handle with both hands. Your arms should still be fully extended.','In one motion, pull the handle up and across your body until your arms are in a fully-extended position above your head.','Keep your back straight and your arms close to your body as you pivot your back foot and straighten your legs to get a full range of motion.','Retract your arms and then your body. Return to the neutral position in a slow and controlled manner.','Repeat to failure.','Then, reposition and repeat the same series of movements on the opposite side.'],'Connect a standard handle on a tower, and move the cable to the lowest pulley position. With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable. Your outstretched arm should be aligned with the cable. With your feet positioned shoulder width apart, squat down and grab the handle with both hands. Your arms should still be fully extended. In one motion, pull the handle up and across your body until your arms are in a fully-extended position above your head. Keep your back straight and your arms close to your body as you pivot your back foot and straighten your legs to get a full range of motion. Retract your arms and then your body. Return to the neutral position in a slow and controlled manner. Repeat to failure. Then, reposition and repeat the same series of movements on the opposite side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Cable_Lift/0.jpg','exercisedb',true);